package com.weeklycommit.rcdo.service;

import com.weeklycommit.domain.entity.RcdoChangeLog;
import com.weeklycommit.domain.entity.RcdoNode;
import com.weeklycommit.domain.enums.RcdoNodeStatus;
import com.weeklycommit.domain.enums.RcdoNodeType;
import com.weeklycommit.domain.repository.RcdoChangeLogRepository;
import com.weeklycommit.domain.repository.RcdoNodeRepository;
import com.weeklycommit.rcdo.dto.CreateRcdoNodeRequest;
import com.weeklycommit.rcdo.dto.RcdoNodeWithPathResponse;
import com.weeklycommit.rcdo.dto.RcdoNodeResponse;
import com.weeklycommit.rcdo.dto.RcdoTreeNodeResponse;
import com.weeklycommit.rcdo.dto.UpdateRcdoNodeRequest;
import com.weeklycommit.rcdo.exception.RcdoValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.util.ArrayList;
import java.util.List;
import java.util.Objects;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class RcdoService {

	private final RcdoNodeRepository nodeRepo;
	private final RcdoChangeLogRepository changeLogRepo;

	public RcdoService(RcdoNodeRepository nodeRepo, RcdoChangeLogRepository changeLogRepo) {
		this.nodeRepo = nodeRepo;
		this.changeLogRepo = changeLogRepo;
	}

	// -------------------------------------------------------------------------
	// Create
	// -------------------------------------------------------------------------

	public RcdoNode createNode(CreateRcdoNodeRequest req, UUID actorUserId) {
		validateParentForType(req.nodeType(), req.parentId());

		RcdoNode node = new RcdoNode();
		node.setNodeType(req.nodeType());
		node.setStatus(RcdoNodeStatus.DRAFT);
		node.setParentId(req.parentId());
		node.setTitle(req.title());
		node.setDescription(req.description());
		node.setOwnerTeamId(req.ownerTeamId());
		node.setOwnerUserId(req.ownerUserId());

		RcdoNode saved = nodeRepo.save(node);
		writeChangeLog(saved.getId(), actorUserId, "CREATED", null,
				jsonField("title", saved.getTitle()));
		return saved;
	}

	// -------------------------------------------------------------------------
	// Read
	// -------------------------------------------------------------------------

	@Transactional(readOnly = true)
	public RcdoNode getNode(UUID id) {
		return findById(id);
	}

	@Transactional(readOnly = true)
	public RcdoNodeWithPathResponse getNodeWithPath(UUID id) {
		RcdoNode node = findById(id);
		List<RcdoNodeResponse> path = buildAncestorPath(node);
		return new RcdoNodeWithPathResponse(RcdoNodeResponse.from(node), path);
	}

	@Transactional(readOnly = true)
	public List<RcdoNode> listNodes(RcdoNodeType type, RcdoNodeStatus status,
			UUID parentId, UUID ownerTeamId) {
		return nodeRepo.findAll().stream()
				.filter(n -> type == null || n.getNodeType() == type)
				.filter(n -> status == null || n.getStatus() == status)
				.filter(n -> parentId == null || Objects.equals(n.getParentId(), parentId))
				.filter(n -> ownerTeamId == null || Objects.equals(n.getOwnerTeamId(), ownerTeamId))
				.toList();
	}

	@Transactional(readOnly = true)
	public List<RcdoTreeNodeResponse> getTree() {
		List<RcdoNode> all = nodeRepo.findAll();
		return buildTree(all, null);
	}

	// -------------------------------------------------------------------------
	// Update
	// -------------------------------------------------------------------------

	public RcdoNode updateNode(UUID id, UpdateRcdoNodeRequest req, UUID actorUserId) {
		RcdoNode node = findById(id);
		StringBuilder changes = new StringBuilder("{");

		if (req.title() != null && !req.title().equals(node.getTitle())) {
			changes.append("\"title\":\"").append(req.title()).append("\",");
			node.setTitle(req.title());
		}
		if (req.description() != null) {
			node.setDescription(req.description());
		}
		if (req.ownerTeamId() != null) {
			node.setOwnerTeamId(req.ownerTeamId());
		}
		if (req.ownerUserId() != null) {
			node.setOwnerUserId(req.ownerUserId());
		}

		RcdoNode saved = nodeRepo.save(node);
		String changesSummary = changes.append("}").toString();
		writeChangeLog(id, actorUserId, "UPDATED", null, changesSummary);
		return saved;
	}

	// -------------------------------------------------------------------------
	// Activate
	// -------------------------------------------------------------------------

	public RcdoNode activateNode(UUID id, UUID actorUserId) {
		RcdoNode node = findById(id);
		if (node.getStatus() == RcdoNodeStatus.ARCHIVED) {
			throw new RcdoValidationException("Cannot activate an archived node");
		}
		if (node.getStatus() == RcdoNodeStatus.ACTIVE) {
			return node; // already active, idempotent
		}
		String oldStatus = node.getStatus().name();
		node.setStatus(RcdoNodeStatus.ACTIVE);
		RcdoNode saved = nodeRepo.save(node);
		writeChangeLog(id, actorUserId, "ACTIVATED",
				jsonField("status", oldStatus),
				jsonField("status", "ACTIVE"));
		return saved;
	}

	// -------------------------------------------------------------------------
	// Archive
	// -------------------------------------------------------------------------

	public RcdoNode archiveNode(UUID id, UUID actorUserId) {
		RcdoNode node = findById(id);
		if (node.getStatus() == RcdoNodeStatus.ARCHIVED) {
			return node; // idempotent
		}

		List<RcdoNode> children = nodeRepo.findByParentId(id);
		boolean hasNonArchivedChildren = children.stream()
				.anyMatch(c -> c.getStatus() != RcdoNodeStatus.ARCHIVED);
		if (hasNonArchivedChildren) {
			throw new RcdoValidationException(
					"Cannot archive node with non-archived children; archive or move them first");
		}

		String oldStatus = node.getStatus().name();
		node.setStatus(RcdoNodeStatus.ARCHIVED);
		RcdoNode saved = nodeRepo.save(node);
		writeChangeLog(id, actorUserId, "ARCHIVED",
				jsonField("status", oldStatus),
				jsonField("status", "ARCHIVED"));
		return saved;
	}

	// -------------------------------------------------------------------------
	// Move
	// -------------------------------------------------------------------------

	public RcdoNode moveNode(UUID id, UUID newParentId, UUID actorUserId) {
		RcdoNode node = findById(id);
		validateParentForType(node.getNodeType(), newParentId);

		UUID oldParentId = node.getParentId();
		node.setParentId(newParentId);
		RcdoNode saved = nodeRepo.save(node);
		writeChangeLog(id, actorUserId, "MOVED",
				jsonField("parentId", oldParentId == null ? "null" : oldParentId.toString()),
				jsonField("parentId", newParentId.toString()));
		return saved;
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	private RcdoNode findById(UUID id) {
		return nodeRepo.findById(id)
				.orElseThrow(() -> new ResourceNotFoundException("RCDO node not found: " + id));
	}

	/**
	 * Enforces the three-level hierarchy invariant:
	 * <ul>
	 *   <li>RALLY_CRY — parentId must be null</li>
	 *   <li>DEFINING_OBJECTIVE — parentId must reference a RALLY_CRY</li>
	 *   <li>OUTCOME — parentId must reference a DEFINING_OBJECTIVE</li>
	 * </ul>
	 */
	void validateParentForType(RcdoNodeType type, UUID parentId) {
		switch (type) {
			case RALLY_CRY -> {
				if (parentId != null) {
					throw new RcdoValidationException(
							"Rally Cry nodes must have no parent (top-level only)");
				}
			}
			case DEFINING_OBJECTIVE -> {
				if (parentId == null) {
					throw new RcdoValidationException(
							"Defining Objective must have a Rally Cry parent");
				}
				RcdoNode parent = findById(parentId);
				if (parent.getNodeType() != RcdoNodeType.RALLY_CRY) {
					throw new RcdoValidationException(
							"Defining Objective parent must be a Rally Cry, got: "
									+ parent.getNodeType());
				}
			}
			case OUTCOME -> {
				if (parentId == null) {
					throw new RcdoValidationException(
							"Outcome must have a Defining Objective parent");
				}
				RcdoNode parent = findById(parentId);
				if (parent.getNodeType() != RcdoNodeType.DEFINING_OBJECTIVE) {
					throw new RcdoValidationException(
							"Outcome parent must be a Defining Objective, got: "
									+ parent.getNodeType());
				}
			}
		}
	}

	private List<RcdoNodeResponse> buildAncestorPath(RcdoNode node) {
		List<RcdoNodeResponse> path = new ArrayList<>();
		UUID currentParentId = node.getParentId();
		while (currentParentId != null) {
			RcdoNode parent = findById(currentParentId);
			path.add(0, RcdoNodeResponse.from(parent));
			currentParentId = parent.getParentId();
		}
		return path;
	}

	private List<RcdoTreeNodeResponse> buildTree(List<RcdoNode> all, UUID parentId) {
		return all.stream()
				.filter(n -> Objects.equals(n.getParentId(), parentId))
				.map(n -> new RcdoTreeNodeResponse(
						n.getId(), n.getNodeType(), n.getStatus(), n.getTitle(),
						buildTree(all, n.getId())))
				.toList();
	}

	private void writeChangeLog(UUID nodeId, UUID actorUserId,
			String summary, String previousValue, String newValue) {
		RcdoChangeLog log = new RcdoChangeLog();
		log.setRcdoNodeId(nodeId);
		log.setChangedByUserId(actorUserId != null ? actorUserId : UUID.fromString("00000000-0000-0000-0000-000000000000"));
		log.setChangeSummary(summary);
		log.setPreviousValue(previousValue);
		log.setNewValue(newValue);
		changeLogRepo.save(log);
	}

	private static String jsonField(String key, String value) {
		return "{\"" + key + "\":\"" + value + "\"}";
	}
}

package com.weeklycommit.rcdo.service;

import com.weeklycommit.domain.entity.RcdoNode;
import com.weeklycommit.domain.enums.RcdoNodeStatus;
import com.weeklycommit.domain.enums.RcdoNodeType;
import com.weeklycommit.domain.repository.RcdoNodeRepository;
import com.weeklycommit.rcdo.exception.RcdoValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Component;
import org.springframework.transaction.annotation.Transactional;

/**
 * Validates whether a given RCDO node is a legal target for a commit link,
 * per PRD §15 linkage rules:
 *
 * <ul>
 *   <li>Rally Cries are never valid direct commit targets.</li>
 *   <li>An Outcome is valid when it is ACTIVE.</li>
 *   <li>A Defining Objective is valid only when it is ACTIVE <em>and</em>
 *       has no ACTIVE child Outcomes.</li>
 * </ul>
 */
@Component
public class RcdoLinkageValidator {

	private final RcdoNodeRepository nodeRepo;

	public RcdoLinkageValidator(RcdoNodeRepository nodeRepo) {
		this.nodeRepo = nodeRepo;
	}

	/**
	 * Throws {@link RcdoValidationException} if the node is not a valid commit
	 * target, or {@link ResourceNotFoundException} if the node does not exist.
	 */
	@Transactional(readOnly = true)
	public void validateCommitLinkage(UUID rcdoNodeId) {
		RcdoNode node = nodeRepo.findById(rcdoNodeId)
				.orElseThrow(() -> new ResourceNotFoundException(
						"RCDO node not found: " + rcdoNodeId));

		if (node.getNodeType() == RcdoNodeType.RALLY_CRY) {
			throw new RcdoValidationException(
					"Commits cannot link directly to a Rally Cry");
		}

		if (node.getStatus() != RcdoNodeStatus.ACTIVE) {
			throw new RcdoValidationException(
					"Commits can only link to ACTIVE RCDO nodes; node status is "
							+ node.getStatus());
		}

		if (node.getNodeType() == RcdoNodeType.DEFINING_OBJECTIVE) {
			List<RcdoNode> activeOutcomes =
					nodeRepo.findByParentIdAndStatus(node.getId(), RcdoNodeStatus.ACTIVE);
			if (!activeOutcomes.isEmpty()) {
				throw new RcdoValidationException(
						"Commits must link to an Outcome when active Outcomes exist "
								+ "under this Defining Objective");
			}
		}
	}

	/**
	 * Returns {@code true} when the node is a valid commit target, {@code false}
	 * for any validation failure (missing node included).
	 */
	@Transactional(readOnly = true)
	public boolean isValidCommitTarget(UUID rcdoNodeId) {
		try {
			validateCommitLinkage(rcdoNodeId);
			return true;
		} catch (RcdoValidationException | ResourceNotFoundException e) {
			return false;
		}
	}
}

package com.weeklycommit.rcdo.controller;

import com.weeklycommit.domain.entity.RcdoNode;
import com.weeklycommit.domain.enums.RcdoNodeStatus;
import com.weeklycommit.domain.enums.RcdoNodeType;
import com.weeklycommit.rcdo.dto.CreateRcdoNodeRequest;
import com.weeklycommit.rcdo.dto.MoveRcdoNodeRequest;
import com.weeklycommit.rcdo.dto.RcdoNodeResponse;
import com.weeklycommit.rcdo.dto.RcdoNodeWithPathResponse;
import com.weeklycommit.rcdo.dto.RcdoTreeNodeResponse;
import com.weeklycommit.rcdo.dto.UpdateRcdoNodeRequest;
import com.weeklycommit.rcdo.service.RcdoService;
import jakarta.validation.Valid;
import java.util.List;
import java.util.UUID;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/rcdo")
public class RcdoController {

	private final RcdoService rcdoService;

	public RcdoController(RcdoService rcdoService) {
		this.rcdoService = rcdoService;
	}

	/** Create a new RCDO node. Returns 201 with the created node. */
	@PostMapping("/nodes")
	public ResponseEntity<RcdoNodeResponse> createNode(
			@Valid @RequestBody CreateRcdoNodeRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		RcdoNode node = rcdoService.createNode(request, actorUserId);
		return ResponseEntity.status(HttpStatus.CREATED).body(RcdoNodeResponse.from(node));
	}

	/** List RCDO nodes, optionally filtered by type, status, parent, or ownerTeam. */
	@GetMapping("/nodes")
	public ResponseEntity<List<RcdoNodeResponse>> listNodes(
			@RequestParam(required = false) RcdoNodeType type,
			@RequestParam(required = false) RcdoNodeStatus status,
			@RequestParam(required = false) UUID parentId,
			@RequestParam(required = false) UUID ownerTeamId) {
		List<RcdoNode> nodes = rcdoService.listNodes(type, status, parentId, ownerTeamId);
		return ResponseEntity.ok(nodes.stream().map(RcdoNodeResponse::from).toList());
	}

	/** Get a single node with its full ancestor path. */
	@GetMapping("/nodes/{id}")
	public ResponseEntity<RcdoNodeWithPathResponse> getNode(@PathVariable UUID id) {
		return ResponseEntity.ok(rcdoService.getNodeWithPath(id));
	}

	/** Update mutable fields of a node. Null fields in the request are ignored. */
	@PutMapping("/nodes/{id}")
	public ResponseEntity<RcdoNodeResponse> updateNode(
			@PathVariable UUID id,
			@RequestBody UpdateRcdoNodeRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		RcdoNode node = rcdoService.updateNode(id, request, actorUserId);
		return ResponseEntity.ok(RcdoNodeResponse.from(node));
	}

	/** Transition a DRAFT node to ACTIVE. */
	@PostMapping("/nodes/{id}/activate")
	public ResponseEntity<RcdoNodeResponse> activateNode(
			@PathVariable UUID id,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		RcdoNode node = rcdoService.activateNode(id, actorUserId);
		return ResponseEntity.ok(RcdoNodeResponse.from(node));
	}

	/** Archive a node. Fails if the node has non-archived children. */
	@PostMapping("/nodes/{id}/archive")
	public ResponseEntity<RcdoNodeResponse> archiveNode(
			@PathVariable UUID id,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		RcdoNode node = rcdoService.archiveNode(id, actorUserId);
		return ResponseEntity.ok(RcdoNodeResponse.from(node));
	}

	/** Re-parent a node within valid hierarchy constraints. */
	@PostMapping("/nodes/{id}/move")
	public ResponseEntity<RcdoNodeResponse> moveNode(
			@PathVariable UUID id,
			@Valid @RequestBody MoveRcdoNodeRequest request,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID actorUserId) {
		RcdoNode node = rcdoService.moveNode(id, request.newParentId(), actorUserId);
		return ResponseEntity.ok(RcdoNodeResponse.from(node));
	}

	/** Return the full hierarchy tree for use in selection UIs. */
	@GetMapping("/tree")
	public ResponseEntity<List<RcdoTreeNodeResponse>> getTree() {
		return ResponseEntity.ok(rcdoService.getTree());
	}
}

package com.weeklycommit.rcdo.controller;

import com.weeklycommit.rcdo.exception.RcdoValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.stream.Collectors;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

@RestControllerAdvice
public class GlobalExceptionHandler {

	@ExceptionHandler(RcdoValidationException.class)
	public ResponseEntity<Map<String, Object>> handleRcdoValidation(
			RcdoValidationException ex) {
		return ResponseEntity.badRequest().body(errorBody(ex.getMessage()));
	}

	@ExceptionHandler(ResourceNotFoundException.class)
	public ResponseEntity<Map<String, Object>> handleNotFound(
			ResourceNotFoundException ex) {
		return ResponseEntity.status(HttpStatus.NOT_FOUND).body(errorBody(ex.getMessage()));
	}

	@ExceptionHandler(MethodArgumentNotValidException.class)
	public ResponseEntity<Map<String, Object>> handleBeanValidation(
			MethodArgumentNotValidException ex) {
		String details = ex.getBindingResult().getFieldErrors().stream()
				.map(fe -> fe.getField() + ": " + fe.getDefaultMessage())
				.collect(Collectors.joining("; "));
		return ResponseEntity.badRequest().body(errorBody(details));
	}

	private static Map<String, Object> errorBody(String message) {
		Map<String, Object> body = new LinkedHashMap<>();
		body.put("error", message);
		return body;
	}
}

