	}

	@Test
	void getNode_notFound_throws() {
		UUID id = UUID.randomUUID();
		when(nodeRepo.findById(id)).thenReturn(Optional.empty());
		assertThatThrownBy(() -> service.getNode(id))
				.isInstanceOf(ResourceNotFoundException.class);
	}
}

