package com.weeklycommit.plan.service;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.lenient;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import com.weeklycommit.domain.entity.UserAccount;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.UserAccountRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

@ExtendWith(MockitoExtension.class)
class WeeklyPlanServiceTest {

	@Mock
	private WeeklyPlanRepository planRepo;

	@Mock
	private UserAccountRepository userRepo;

	@Mock
	private WeeklyCommitRepository commitRepo;

	@InjectMocks
	private WeeklyPlanService service;

	private final UUID userId = UUID.randomUUID();
	private final UUID teamId = UUID.randomUUID();
	private final LocalDate monday = LocalDate.of(2025, 6, 2); // a Monday

	private UserAccount userWithTeam() {
		UserAccount u = new UserAccount();
		u.setId(userId);
		u.setHomeTeamId(teamId);
		u.setWeeklyCapacityPoints(10);
		return u;
	}

	@BeforeEach
	void stubSave() {
		lenient().when(planRepo.save(any(WeeklyPlan.class))).thenAnswer(inv -> {
			WeeklyPlan p = inv.getArgument(0);
			if (p.getId() == null) {
				p.setId(UUID.randomUUID());
			}
			return p;
		});
		lenient().when(commitRepo.findByPlanIdOrderByPriorityOrder(any())).thenReturn(List.of());
	}

	// -------------------------------------------------------------------------
	// getOrCreatePlan
	// -------------------------------------------------------------------------

	@Test
	void getOrCreate_existingPlan_returnsExisting() {
		WeeklyPlan existing = new WeeklyPlan();
		existing.setId(UUID.randomUUID());
		existing.setOwnerUserId(userId);
		existing.setWeekStartDate(monday);
		existing.setState(PlanState.DRAFT);

		when(planRepo.findByOwnerUserIdAndWeekStartDate(userId, monday))
				.thenReturn(Optional.of(existing));

		WeeklyPlan result = service.getOrCreatePlan(userId, monday);

		assertThat(result.getId()).isEqualTo(existing.getId());
		verify(planRepo, never()).save(any());
	}

	@Test
	void getOrCreate_noPlan_createsNewDraftPlan() {
		when(planRepo.findByOwnerUserIdAndWeekStartDate(userId, monday))
				.thenReturn(Optional.empty());
		when(userRepo.findById(userId)).thenReturn(Optional.of(userWithTeam()));

		WeeklyPlan result = service.getOrCreatePlan(userId, monday);

		assertThat(result.getState()).isEqualTo(PlanState.DRAFT);
		assertThat(result.getOwnerUserId()).isEqualTo(userId);
		assertThat(result.getTeamId()).isEqualTo(teamId);
		assertThat(result.getWeekStartDate()).isEqualTo(monday);
		verify(planRepo).save(any());
	}

	@Test
	void getOrCreate_snapshotsCapacityFromUser() {
		UserAccount user = userWithTeam();
		user.setWeeklyCapacityPoints(8);
		when(planRepo.findByOwnerUserIdAndWeekStartDate(userId, monday))
				.thenReturn(Optional.empty());
		when(userRepo.findById(userId)).thenReturn(Optional.of(user));

		WeeklyPlan result = service.getOrCreatePlan(userId, monday);

		assertThat(result.getCapacityBudgetPoints()).isEqualTo(8);
	}

	@Test
	void getOrCreate_userNotFound_throws() {
		when(planRepo.findByOwnerUserIdAndWeekStartDate(userId, monday))
				.thenReturn(Optional.empty());
		when(userRepo.findById(userId)).thenReturn(Optional.empty());

		assertThatThrownBy(() -> service.getOrCreatePlan(userId, monday))
				.isInstanceOf(ResourceNotFoundException.class);
	}

	@Test
	void getOrCreate_userWithNoHomeTeam_throws() {
		UserAccount user = new UserAccount();
		user.setId(userId);
		user.setHomeTeamId(null); // no team
		user.setWeeklyCapacityPoints(10);

		when(planRepo.findByOwnerUserIdAndWeekStartDate(userId, monday))
				.thenReturn(Optional.empty());
		when(userRepo.findById(userId)).thenReturn(Optional.of(user));

		assertThatThrownBy(() -> service.getOrCreatePlan(userId, monday))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("home team");
	}

	// -------------------------------------------------------------------------
	// listPlansForUser
	// -------------------------------------------------------------------------

	@Test
	void listPlans_returnsPlansInDescendingOrder() {
		WeeklyPlan p1 = new WeeklyPlan();
		p1.setId(UUID.randomUUID());
		p1.setOwnerUserId(userId);
		p1.setWeekStartDate(monday);
		p1.setState(PlanState.DRAFT);

		when(planRepo.findByOwnerUserIdOrderByWeekStartDateDesc(userId)).thenReturn(List.of(p1));

		var result = service.listPlansForUser(userId);
		assertThat(result).hasSize(1);
	}

	// -------------------------------------------------------------------------
	// currentWeekStart
	// -------------------------------------------------------------------------

	@Test
	void currentWeekStart_isAlwaysMonday() {
		LocalDate result = WeeklyPlanService.currentWeekStart();
		assertThat(result.getDayOfWeek()).isEqualTo(DayOfWeek.MONDAY);
	}
}

package com.weeklycommit.plan.service;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.lenient;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.plan.dto.CreateCommitRequest;
import com.weeklycommit.plan.dto.UpdateCommitRequest;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.rcdo.exception.RcdoValidationException;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import com.weeklycommit.rcdo.service.RcdoLinkageValidator;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

@ExtendWith(MockitoExtension.class)
class CommitServiceTest {

	@Mock
	private WeeklyCommitRepository commitRepo;

	@Mock
	private WeeklyPlanRepository planRepo;

	@Mock
	private WorkItemRepository workItemRepo;

	@Mock
	private RcdoLinkageValidator rcdoLinkageValidator;

	@InjectMocks
	private CommitService service;

	private final UUID planId = UUID.randomUUID();
	private final UUID actorId = UUID.randomUUID();

	// -------------------------------------------------------------------------
	// Test helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan draftPlan() {
		WeeklyPlan p = new WeeklyPlan();
		p.setId(planId);
		p.setOwnerUserId(actorId);
		p.setTeamId(UUID.randomUUID());
		p.setWeekStartDate(LocalDate.of(2025, 6, 2));
		p.setState(PlanState.DRAFT);
		p.setCapacityBudgetPoints(10);
		return p;
	}

	private WeeklyPlan lockedPlan() {
		WeeklyPlan p = draftPlan();
		p.setState(PlanState.LOCKED);
		return p;
	}

	private WeeklyCommit commit(ChessPiece piece) {
		WeeklyCommit c = new WeeklyCommit();
		c.setId(UUID.randomUUID());
		c.setPlanId(planId);
		c.setOwnerUserId(actorId);
		c.setTitle("Test commit");
		c.setChessPiece(piece);
		c.setPriorityOrder(1);
		return c;
	}

	private CreateCommitRequest req(ChessPiece piece, String criteria) {
		return new CreateCommitRequest("Ship feature", piece, null, null, null, null, criteria);
	}

	@BeforeEach
	void stubSave() {
		lenient().when(commitRepo.save(any(WeeklyCommit.class))).thenAnswer(inv -> {
			WeeklyCommit c = inv.getArgument(0);
			if (c.getId() == null) c.setId(UUID.randomUUID());
			return c;
		});
	}

	// -------------------------------------------------------------------------
	// createCommit — plan state
	// -------------------------------------------------------------------------

	@Test
	void createCommit_draftPlan_succeeds() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());
		when(commitRepo.countByPlanId(planId)).thenReturn(0L);

		WeeklyCommit result = service.createCommit(planId, req(ChessPiece.ROOK, null), actorId);
		assertThat(result.getChessPiece()).isEqualTo(ChessPiece.ROOK);
	}

	@Test
	void createCommit_lockedPlan_throws() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(lockedPlan()));

		assertThatThrownBy(() -> service.createCommit(planId, req(ChessPiece.ROOK, null), actorId))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("DRAFT");
	}

	// -------------------------------------------------------------------------
	// createCommit — chess piece limits
	// -------------------------------------------------------------------------

	@Test
	void createCommit_firstKing_succeeds() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());
		when(commitRepo.countByPlanId(planId)).thenReturn(0L);

		WeeklyCommit result = service.createCommit(planId, req(ChessPiece.KING, "Must succeed"),
				actorId);
		assertThat(result.getChessPiece()).isEqualTo(ChessPiece.KING);
	}

	@Test
	void createCommit_secondKing_throws() {
		WeeklyCommit existingKing = commit(ChessPiece.KING);
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of(existingKing));

		assertThatThrownBy(
				() -> service.createCommit(planId, req(ChessPiece.KING, "Another king"), actorId))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("King");
	}

	@Test
	void createCommit_twoQueens_secondQueenSucceeds() {
		WeeklyCommit q1 = commit(ChessPiece.QUEEN);
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of(q1));
		when(commitRepo.countByPlanId(planId)).thenReturn(1L);

		WeeklyCommit result = service.createCommit(planId, req(ChessPiece.QUEEN, "Q2 criteria"),
				actorId);
		assertThat(result.getChessPiece()).isEqualTo(ChessPiece.QUEEN);
	}

	@Test
	void createCommit_thirdQueen_throws() {
		WeeklyCommit q1 = commit(ChessPiece.QUEEN);
		WeeklyCommit q2 = commit(ChessPiece.QUEEN);
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of(q1, q2));

		assertThatThrownBy(
				() -> service.createCommit(planId, req(ChessPiece.QUEEN, "Q3 criteria"), actorId))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("Queen");
	}

	// -------------------------------------------------------------------------
	// createCommit — estimate validation
	// -------------------------------------------------------------------------

	@Test
	void createCommit_validEstimatePoints_succeeds() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());
		when(commitRepo.countByPlanId(planId)).thenReturn(0L);

		CreateCommitRequest req =
				new CreateCommitRequest("Task", ChessPiece.ROOK, null, null, null, 5, null);
		WeeklyCommit result = service.createCommit(planId, req, actorId);
		assertThat(result.getEstimatePoints()).isEqualTo(5);
	}

	@Test
	void createCommit_invalidEstimatePoints_throws() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());

		CreateCommitRequest req =
				new CreateCommitRequest("Task", ChessPiece.ROOK, null, null, null, 4, null);
		assertThatThrownBy(() -> service.createCommit(planId, req, actorId))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("Estimate points");
	}

	// -------------------------------------------------------------------------
	// createCommit — success criteria
	// -------------------------------------------------------------------------

	@Test
	void createCommit_kingWithoutSuccessCriteria_throws() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());

		assertThatThrownBy(() -> service.createCommit(planId, req(ChessPiece.KING, null), actorId))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("Success criteria");
	}

	@Test
	void createCommit_queenWithoutSuccessCriteria_throws() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());

		assertThatThrownBy(() -> service.createCommit(planId, req(ChessPiece.QUEEN, null), actorId))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("Success criteria");
	}

	@Test
	void createCommit_rookWithoutSuccessCriteria_succeeds() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());
		when(commitRepo.countByPlanId(planId)).thenReturn(0L);

		WeeklyCommit result = service.createCommit(planId, req(ChessPiece.ROOK, null), actorId);
		assertThat(result.getChessPiece()).isEqualTo(ChessPiece.ROOK);
	}

	// -------------------------------------------------------------------------
	// createCommit — RCDO linkage
	// -------------------------------------------------------------------------

	@Test
	void createCommit_invalidRcdo_throws() {
		UUID rcdoId = UUID.randomUUID();
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());
		doThrow(new RcdoValidationException("Not a valid target"))
				.when(rcdoLinkageValidator).validateCommitLinkage(rcdoId);

		CreateCommitRequest req =
				new CreateCommitRequest("Task", ChessPiece.ROOK, null, rcdoId, null, null, null);
		assertThatThrownBy(() -> service.createCommit(planId, req, actorId))
				.isInstanceOf(RcdoValidationException.class);
	}

	@Test
	void createCommit_noRcdo_doesNotValidateLinkage() {
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());
		when(commitRepo.countByPlanId(planId)).thenReturn(0L);

		service.createCommit(planId, req(ChessPiece.ROOK, null), actorId);
		verify(rcdoLinkageValidator, never()).validateCommitLinkage(any());
	}

	// -------------------------------------------------------------------------
	// updateCommit
	// -------------------------------------------------------------------------

	@Test
	void updateCommit_draftPlan_changesTitle() {
		WeeklyCommit c = commit(ChessPiece.ROOK);
		when(commitRepo.findById(c.getId())).thenReturn(Optional.of(c));
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));

		UpdateCommitRequest req =
				new UpdateCommitRequest("New Title", null, null, null, null, null, null);
		WeeklyCommit result = service.updateCommit(c.getId(), req, actorId);
		assertThat(result.getTitle()).isEqualTo("New Title");
	}

	@Test
	void updateCommit_lockedPlan_throws() {
		WeeklyCommit c = commit(ChessPiece.ROOK);
		when(commitRepo.findById(c.getId())).thenReturn(Optional.of(c));
		when(planRepo.findById(planId)).thenReturn(Optional.of(lockedPlan()));

		assertThatThrownBy(() -> service.updateCommit(c.getId(),
				new UpdateCommitRequest("T", null, null, null, null, null, null), actorId))
				.isInstanceOf(PlanValidationException.class);
	}

	@Test
	void updateCommit_changingChessToKing_revalidatesLimits() {
		WeeklyCommit existingKing = commit(ChessPiece.KING);
		WeeklyCommit rookToChange = commit(ChessPiece.ROOK);
		rookToChange.setId(UUID.randomUUID());

		when(commitRepo.findById(rookToChange.getId())).thenReturn(Optional.of(rookToChange));
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId))
				.thenReturn(List.of(existingKing, rookToChange));

		UpdateCommitRequest req =
				new UpdateCommitRequest(null, ChessPiece.KING, null, null, null, null, "Criteria");
		assertThatThrownBy(() -> service.updateCommit(rookToChange.getId(), req, actorId))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("King");
	}

	// -------------------------------------------------------------------------
	// deleteCommit
	// -------------------------------------------------------------------------

	@Test
	void deleteCommit_draftPlan_removesCommit() {
		WeeklyCommit c = commit(ChessPiece.ROOK);
		when(commitRepo.findById(c.getId())).thenReturn(Optional.of(c));
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of());

		service.deleteCommit(c.getId(), actorId);
		verify(commitRepo).delete(c);
	}

	@Test
	void deleteCommit_renumbersRemaining() {
		WeeklyCommit c1 = commit(ChessPiece.ROOK);
		c1.setPriorityOrder(1);
		WeeklyCommit c2 = commit(ChessPiece.BISHOP);
		c2.setPriorityOrder(2);
		WeeklyCommit c3 = commit(ChessPiece.PAWN);
		c3.setPriorityOrder(3);

		// Deleting c2; remaining = [c1, c3]
		when(commitRepo.findById(c2.getId())).thenReturn(Optional.of(c2));
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of(c1, c3));

		service.deleteCommit(c2.getId(), actorId);

		assertThat(c1.getPriorityOrder()).isEqualTo(1);
		assertThat(c3.getPriorityOrder()).isEqualTo(2);
	}

	// -------------------------------------------------------------------------
	// reorderCommits
	// -------------------------------------------------------------------------

	@Test
	void reorderCommits_validOrder_appliesNewOrder() {
		WeeklyCommit c1 = commit(ChessPiece.ROOK);
		c1.setPriorityOrder(1);
		WeeklyCommit c2 = commit(ChessPiece.BISHOP);
		c2.setPriorityOrder(2);

		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId))
				.thenReturn(new ArrayList<>(List.of(c1, c2)));

		// Reverse order: c2 first
		service.reorderCommits(planId, List.of(c2.getId(), c1.getId()), actorId);

		assertThat(c2.getPriorityOrder()).isEqualTo(1);
		assertThat(c1.getPriorityOrder()).isEqualTo(2);
	}

	@Test
	void reorderCommits_missingCommitId_throws() {
		WeeklyCommit c1 = commit(ChessPiece.ROOK);
		when(planRepo.findById(planId)).thenReturn(Optional.of(draftPlan()));
		when(commitRepo.findByPlanIdOrderByPriorityOrder(planId)).thenReturn(List.of(c1));

		// Providing a random UUID not in the plan
		assertThatThrownBy(() -> service.reorderCommits(planId,
				List.of(c1.getId(), UUID.randomUUID()), actorId))
				.isInstanceOf(PlanValidationException.class)
				.hasMessageContaining("Reorder list");
	}

	// -------------------------------------------------------------------------
	// Direct validation helper tests
	// -------------------------------------------------------------------------

	@Test
	void validateEstimatePoints_nullValue_passes() {
		service.validateEstimatePoints(null); // no exception
	}

	@Test
	void validateSuccessCriteria_bishopWithoutCriteria_passes() {
		service.validateSuccessCriteria(ChessPiece.BISHOP, null); // no exception
	}
}

package com.weeklycommit.plan.controller;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.delete;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.PlanState;
import com.weeklycommit.plan.dto.CommitResponse;
import com.weeklycommit.plan.dto.CreateCommitRequest;
import com.weeklycommit.plan.dto.CreatePlanRequest;
import com.weeklycommit.plan.dto.PlanResponse;
import com.weeklycommit.plan.dto.PlanWithCommitsResponse;
import com.weeklycommit.plan.dto.ReorderCommitsRequest;
import com.weeklycommit.plan.exception.PlanValidationException;
import com.weeklycommit.plan.service.CommitService;
import com.weeklycommit.plan.service.WeeklyPlanService;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.time.Instant;
import java.time.LocalDate;
import java.util.List;
import java.util.UUID;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

@WebMvcTest(PlanController.class)
class PlanControllerTest {

	@Autowired
	private MockMvc mockMvc;

	@MockBean
	private WeeklyPlanService planService;

	@MockBean
	private CommitService commitService;

	@Autowired
	private ObjectMapper objectMapper;

	// -------------------------------------------------------------------------
	// Helpers
	// -------------------------------------------------------------------------

	private WeeklyPlan samplePlan() {
		WeeklyPlan p = new WeeklyPlan();
		p.setId(UUID.randomUUID());
		p.setOwnerUserId(UUID.randomUUID());
		p.setTeamId(UUID.randomUUID());
		p.setWeekStartDate(LocalDate.of(2025, 6, 2));
		p.setState(PlanState.DRAFT);
		p.setCapacityBudgetPoints(10);
		p.setLockDeadline(Instant.now());
		p.setReconcileDeadline(Instant.now());
		return p;
	}

	private PlanWithCommitsResponse planResp(WeeklyPlan plan) {
		return new PlanWithCommitsResponse(PlanResponse.from(plan), List.of(), 0);
	}

	private WeeklyCommit sampleCommit(UUID planId) {
		WeeklyCommit c = new WeeklyCommit();
		c.setId(UUID.randomUUID());
		c.setPlanId(planId);
		c.setOwnerUserId(UUID.randomUUID());
		c.setTitle("Test commit");
		c.setChessPiece(ChessPiece.ROOK);
		c.setPriorityOrder(1);
		return c;
	}

	// -------------------------------------------------------------------------
	// GET /api/plans
	// -------------------------------------------------------------------------

	@Test
	void listPlans_returns200() throws Exception {
		UUID userId = UUID.randomUUID();
		WeeklyPlan plan = samplePlan();
		when(planService.listPlansForUser(userId)).thenReturn(List.of(PlanResponse.from(plan)));

		mockMvc.perform(get("/api/plans").param("userId", userId.toString()))
				.andExpect(status().isOk())
				.andExpect(jsonPath("$[0].state").value("DRAFT"));
	}

	// -------------------------------------------------------------------------
	// POST /api/plans
	// -------------------------------------------------------------------------

	@Test
	void getOrCreate_returns200() throws Exception {
		UUID userId = UUID.randomUUID();
		WeeklyPlan plan = samplePlan();
		when(planService.getOrCreatePlan(eq(userId), any())).thenReturn(plan);
		when(planService.getPlanWithCommits(plan.getId())).thenReturn(planResp(plan));

		CreatePlanRequest req = new CreatePlanRequest(userId, null);
		mockMvc.perform(post("/api/plans")
				.contentType(MediaType.APPLICATION_JSON)
				.content(objectMapper.writeValueAsString(req)))
				.andExpect(status().isOk())
				.andExpect(jsonPath("$.plan.state").value("DRAFT"));
	}

	@Test
	void getOrCreate_userNotFound_returns404() throws Exception {
		UUID userId = UUID.randomUUID();
		when(planService.getOrCreatePlan(eq(userId), any()))
				.thenThrow(new ResourceNotFoundException("User not found: " + userId));

		CreatePlanRequest req = new CreatePlanRequest(userId, null);
		mockMvc.perform(post("/api/plans")
				.contentType(MediaType.APPLICATION_JSON)
				.content(objectMapper.writeValueAsString(req)))
				.andExpect(status().isNotFound());
	}

	// -------------------------------------------------------------------------
	// GET /api/plans/{id}
	// -------------------------------------------------------------------------

	@Test
	void getPlan_found_returns200() throws Exception {
		WeeklyPlan plan = samplePlan();
		when(planService.getPlanWithCommits(plan.getId())).thenReturn(planResp(plan));

		mockMvc.perform(get("/api/plans/" + plan.getId()))
				.andExpect(status().isOk())
				.andExpect(jsonPath("$.plan.id").value(plan.getId().toString()));
	}

	@Test
	void getPlan_notFound_returns404() throws Exception {
		UUID id = UUID.randomUUID();
		when(planService.getPlanWithCommits(id))
				.thenThrow(new ResourceNotFoundException("not found"));

		mockMvc.perform(get("/api/plans/" + id))
				.andExpect(status().isNotFound());
	}

	// -------------------------------------------------------------------------
	// POST /api/plans/{planId}/commits
	// -------------------------------------------------------------------------

	@Test
	void createCommit_validRequest_returns201() throws Exception {
		WeeklyPlan plan = samplePlan();
		WeeklyCommit commit = sampleCommit(plan.getId());
		when(commitService.createCommit(eq(plan.getId()), any(), any())).thenReturn(commit);

		CreateCommitRequest req =
				new CreateCommitRequest("Task", ChessPiece.ROOK, null, null, null, null, null);
		mockMvc.perform(post("/api/plans/" + plan.getId() + "/commits")
				.contentType(MediaType.APPLICATION_JSON)
				.content(objectMapper.writeValueAsString(req)))
				.andExpect(status().isCreated())
				.andExpect(jsonPath("$.chessPiece").value("ROOK"));
	}

	@Test
	void createCommit_kingLimitExceeded_returns400() throws Exception {
		UUID planId = UUID.randomUUID();
		when(commitService.createCommit(eq(planId), any(), any()))
				.thenThrow(new PlanValidationException("King limit exceeded"));

		CreateCommitRequest req =
				new CreateCommitRequest("King", ChessPiece.KING, null, null, null, null, "Criteria");
		mockMvc.perform(post("/api/plans/" + planId + "/commits")
				.contentType(MediaType.APPLICATION_JSON)
				.content(objectMapper.writeValueAsString(req)))
				.andExpect(status().isBadRequest())
				.andExpect(jsonPath("$.error").exists());
	}

	// -------------------------------------------------------------------------
	// DELETE /api/plans/{planId}/commits/{commitId}
	// -------------------------------------------------------------------------

	@Test
	void deleteCommit_success_returns204() throws Exception {
		UUID planId = UUID.randomUUID();
		UUID commitId = UUID.randomUUID();

		mockMvc.perform(delete("/api/plans/" + planId + "/commits/" + commitId))
				.andExpect(status().isNoContent());
	}

	// -------------------------------------------------------------------------
	// PUT /api/plans/{planId}/commits/reorder
	// -------------------------------------------------------------------------

	@Test
	void reorderCommits_validRequest_returns200() throws Exception {
		WeeklyPlan plan = samplePlan();
		WeeklyCommit c = sampleCommit(plan.getId());
		when(commitService.reorderCommits(eq(plan.getId()), any(), any())).thenReturn(List.of(c));
		when(planService.getPlanWithCommits(plan.getId())).thenReturn(
				new PlanWithCommitsResponse(PlanResponse.from(plan),
						List.of(CommitResponse.from(c)), 0));

		ReorderCommitsRequest req = new ReorderCommitsRequest(List.of(c.getId()));
		mockMvc.perform(put("/api/plans/" + plan.getId() + "/commits/reorder")
				.contentType(MediaType.APPLICATION_JSON)
				.content(objectMapper.writeValueAsString(req)))
				.andExpect(status().isOk())
				.andExpect(jsonPath("$.commits[0].id").value(c.getId().toString()));
	}

	@Test
	void reorderCommits_emptyList_returns400() throws Exception {
		UUID planId = UUID.randomUUID();
		ReorderCommitsRequest req = new ReorderCommitsRequest(List.of());

		mockMvc.perform(put("/api/plans/" + planId + "/commits/reorder")
				.contentType(MediaType.APPLICATION_JSON)
				.content(objectMapper.writeValueAsString(req)))
				.andExpect(status().isBadRequest());
	}
}

